struct KVCache {
    std::vector<float> K;
    std::vector<float> V;
    size_t head_dim;
    size_t max_tokens;
};

void kv_init(KVCache& kv, size_t heads, size_t dim, size_t max_tokens) {
    kv.head_dim = dim;
    kv.max_tokens = max_tokens;
    kv.K.resize(heads * dim * max_tokens);
    kv.V.resize(heads * dim * max_tokens);
